class DSU:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            if self.rank[root_i] < self.rank[root_j]:
                self.parent[root_i] = root_j
            elif self.rank[root_j] < self.rank[root_i]:
                self.parent[root_j] = root_i
            else:
                self.parent[root_j] = root_i
                self.rank[root_i] += 1
            return True
        return False

def minCostConnectCities(n, connections):
    # connections: list of [city1, city2, cost]

    edges = []
    for u, v, cost in connections:
        edges.append((cost, u, v))

    edges.sort()

    dsu = DSU(n)
    min_cost = 0
    num_edges_in_mst = 0

    for cost, u, v in edges:
        if dsu.union(u, v):
            min_cost += cost
            num_edges_in_mst += 1
            if num_edges_in_mst == n - 1:
                break

    # If the graph is disconnected and not all cities can be connected,
    # or if n=0 or n=1, handle those cases.
    if n <= 1:
        return 0

    # If after iterating through all edges, not n-1 edges are added,
    # it means not all cities could be connected. 
    # The problem implies all cities can be connected, so this check might not be strictly necessary
    # depending on problem constraints, but it's good practice.
    if num_edges_in_mst < n - 1:
        # This implies it's impossible to connect all cities.
        # A common return value for this scenario might be -1 or raise an error,
        # but typically for MST problems, it's assumed a connected graph is given.
        pass # For this problem, we assume it's always possible.

    return min_cost
